INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6e2f88c7-moex-00076', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於代理之敘述，何者錯誤？', '["甲對於自己5歲兒子贈送房屋，係屬自己代理", "乙擅自以丙之名義，將丙收藏之名畫出售於惡意丁，並交付之。乙之行為係無權代理，效力未定", "甲委託乙購買一克拉鑽戒，並授與代理權。乙以甲之名義，與丙訂立購買鑽戒之契約。未料， 乙受到丙詐欺，買到假鑽戒。因此，甲得撤銷該買賣契約", "甲授與代理權於17歲乙代為購買機車，但乙之父母並不知情。因為該代理權授與，須以意思 表示為之，所以在乙之父母未同意前，乙之代理行為效力未定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00077', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列何者所附之條件為有效？', '["甲乙協議離婚，約定甲應給付乙新臺幣（下同）1,000萬元，該離婚始生效力", "甲毆傷乙，乙提出傷害告訴後，雙方協議離婚，約定以乙撤回告訴為條件，作為離婚之條件", "甲與丙有婚外情，約定甲給付丙1,000萬元，以繼續維持該婚外情關係", "甲與丙協議結束婚外情，約定甲應給付丙1,000萬元，該協議始生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00078', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於遺產管理人職務之敘述，何者錯誤？', '["編製遺產清冊，並為保存遺產必要之處置。遺產清冊，管理人應於就職後三個月內編製之", "聲請法院依公示催告程序，限定六個月以上之期間，公告被繼承人之債權人及受遺贈人，命其 於該期間內報明債權及為願受遺贈與否之聲明，被繼承人之債權人及受遺贈人為管理人所已知 者，應分別通知之", "清償債權或交付遺贈物", "有繼承人承認繼承或遺產歸屬國庫時，為遺產之移交"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00079', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲、乙二人因買賣契約涉訟，就價金金額，於該契約中竟然同時列有新臺幣（下同）34,500元及 三萬五千四百元二種不同表示。法院應首先如何認定該契約之價金？', '["逕以34,500元為準", "逕以三萬五千四百元為準", "以34,500元與三萬五千四百元的平均數為準", "應先探求當事人原意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00080', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '就甲對乙負有包含原本、利息及費用在內之債務，如甲提出之給付不足清償全部債額之情形，依 民法規定，下列敘述，何者正確？', '["甲、乙得以合意決定抵充順序，無合意時，由甲指定抵充順序", "甲、乙得以合意決定抵充順序，無合意時，由乙指定抵充順序", "甲、乙得以合意決定抵充順序，無合意時，應依費用、利息、原本順序抵充", "甲、乙不得以合意決定抵充順序，其抵充順序僅得由甲指定，乙不得拒絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00081', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲委託乙伺機對與甲素有嫌隙之丙施加暴力、並付訖新臺幣（下同）10萬元為報酬。但乙事後心 生畏懼，並未於約定期限前對丙施加任何暴力行為。下列敘述，何者正確？', '["甲乙間之約定違反公序良俗而無效，乙應返還10萬元於甲", "甲係基於不法原因支付於乙，不得請求乙返還10萬元", "乙應對甲負債務不履行責任，甲得解除契約，請求乙返還10萬元", "乙以欺罔行為使甲陷於錯誤，甲得撤銷委託之意思表示，請求乙返還10萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00082', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於使用借貸之敘述，何者錯誤？', '["使用借貸為債權契約，非物權契約", "使用借貸於借用人使用完畢後，借用人應返還同種類、品質、數量之物", "使用借貸為不要式契約、無償契約", "使用借貸預約成立後，預約貸與人得撤銷其約定。但預約借用人已請求履行預約而預約貸與人 未即時撤銷者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00083', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於租賃物修繕之敘述，何者錯誤？', '["出租人為保存租賃物所為之必要修繕行為，承租人不得拒絕", "租賃關係存續中，租賃物如有修繕之必要，應由出租人負擔者，承租人得自己逕行修繕而請求 出租人償還其費用或於租金中扣除之", "如無修繕之可能者，出租人不負修繕義務", "營業租賃之租賃物之修繕，得約定由承租人負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00084', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於合夥之敘述，何者正確？', '["若合夥契約未特別訂定，合夥人之出資，得以勞務或信用代之", "若合夥契約未特別訂定，各合夥人之出資及其他合夥財產，為合夥人全體之分別共有", "合夥人除契約另有訂定外，負有於約定出資之外增加出資之義務", "合夥人除契約另有訂定外，因損失而致資本減少者，合夥人有補充之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00085', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲有A地，與乙訂立A地買賣契約。嗣後，因丙出價更高，甲又與丙訂立A地買賣契約。下列 敘述，何者正確？', '["甲與丙及甲與乙之A地買賣契約皆為有效", "甲得解除與乙之買賣契約", "乙得主張甲與丙之買賣無效", "甲與丙訂立契約之行為，構成無權處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
